body:
Version: verilator-4.104

I have 2 tests, the only difference is the assertion of the signal `out`, but the results are different.

> test1, code:
``` verilog
module t (input   clk);

reg     in;
wire    out;
integer cyc = 0;

always @ (posedge clk) begin
    cyc <= cyc + 1;
    $write("cyc = %d  in = %x  out = %x\n", cyc, in, out);
end

always @ (posedge clk) begin
    if (cyc == 0)
        in <= 1'b1;
    else if (cyc == 1)
        in <= 1'b0;
//    else if (cyc == 2)
//        if (out != 1'b1) $stop;
//    else if (cyc == 3)
//        if (out != 1'b0) $stop;
    else if (cyc == 9)
        $finish;
end

reg internal;
assign out = internal ^ clk;
always @ (posedge clk) begin
    internal <= in;
end

endmodule
```

> test1, running result:
``` txt
cyc =           0  in = 0  out = 1
cyc =           1  in = 1  out = 1
cyc =           2  in = 0  out = 0
cyc =           3  in = 0  out = 1
cyc =           4  in = 0  out = 1
cyc =           5  in = 0  out = 1
cyc =           6  in = 0  out = 1
cyc =           7  in = 0  out = 1
cyc =           8  in = 0  out = 1
cyc =           9  in = 0  out = 1
``` 
--- 
> test2, code:
``` verilog
module t (input   clk);

reg     in;
wire    out;
integer cyc = 0;

always @ (posedge clk) begin
    cyc <= cyc + 1;
    $write("cyc = %d  in = %x  out = %x\n", cyc, in, out);
end

always @ (posedge clk) begin
    if (cyc == 0)
        in <= 1'b1;
    else if (cyc == 1)
        in <= 1'b0;
    else if (cyc == 2)
        if (out != 1'b1) $stop;
    else if (cyc == 3)
        if (out != 1'b0) $stop;
    else if (cyc == 9)
        $finish;
end

reg internal;
assign out = internal ^ clk;
always @ (posedge clk) begin
    internal <= in;
end

endmodule
```

> test2, running result:
```txt
cyc =           0  in = 0  out = 0
cyc =           1  in = 1  out = 0
cyc =           2  in = 0  out = 1
cyc =           3  in = 0  out = 0
cyc =           4  in = 0  out = 0
cyc =           5  in = 0  out = 0
cyc =           6  in = 0  out = 0
cyc =           7  in = 0  out = 0
cyc =           8  in = 0  out = 0
cyc =           9  in = 0  out = 0
```

I extracted this test from your test `t_gen_intdot`.
As you can see, test2 just uncomment the assertion code, and the output of the signal `out` are opposite.

What do you think of this results of tests?
